func:
// node-red-contrib-opcua는 msg.topic에 NodeId, payload에 interval 등을 사용합니다.
// 여기서는 readmultiple/subscribe를 쉽게 쓰기 위해 item 리스트를 msg.payload로 구성합니다.
// NOTE: opcua-dummy 서버는 namespace index가 보통 2로 올라옵니다.
//       Browse로 확인 후 ns=2가 아니면 아래 ns를 바꾸세요.
const ns = 2;
const base = `ns=${ns};s=`;

msg.payload = [
  { item: base + 'PLC_001.temperature_c', datatype: 'Double' },
  { item: base + 'PLC_001.pressure_bar', datatype: 'Double' },
  { item: base + 'PLC_001.motor_rpm', datatype: 'Int64' },
  { item: base + 'PLC_001.alarm', datatype: 'Boolean' },
];

// 구독 interval(모니터링 주기)
msg.interval = 1000; // ms
return msg;

// node-red-contrib-opcua subscribe 출력은 msg.topic(NodeId) / msg.payload(value) 형태가 일반적입니다.
// 여기서는 토픽을 fdc/plc/PLC-001/<tag>로 정규화하고, payload는 JSON으로 만듭니다.

const nodeId = (msg.topic || '').toString();

// nodeId 예: ns=2;s=PLC_001.temperature_c
let tag = nodeId;
const m = nodeId.match(/s=PLC_001\.(.+)$/);
if (m && m[1]) tag = m[1];

const value = msg.payload;

msg.topic = `fdc/plc/PLC-001/${tag}`;
msg.payload = {
  tag,
  value,
  ts: Date.now(),
  device_id: 'PLC-001'
};
return msg;
